class NormalizedCrossCorrelation2d(torch.nn.Module):
    """Compute Normalized Cross Correlation between two batches of images with circular mask."""

    def __init__(self, patch_size=None, eps=1e-5, image_size=256, radius=121, device=torch.device('cpu')):
        super().__init__()
        self.patch_size = patch_size
        self.eps = eps
        self.image_size = image_size
        self.radius = radius
        self.register_buffer('mask', self.create_circle_mask(image_size, radius).to(device))
        self.mask_sum = self.mask.sum(dim=[-2, -1], keepdim=True)

    @staticmethod
    def create_circle_mask(image_size, radius):
        center = (image_size - 1) / 2  # Center at 127.5 for 256x256
        y = torch.arange(image_size, dtype=torch.float32)
        x = torch.arange(image_size, dtype=torch.float32)
        yy, xx = torch.meshgrid(y, x, indexing='ij')
        dist_sq = (xx - center) ** 2 + (yy - center) ** 2
        mask = (dist_sq <= radius ** 2).float()
        return mask.unsqueeze(0).unsqueeze(0)  # Shape: (1, 1, H, W)

    def forward(self, x1, x2):
        if self.patch_size is not None:
            x1 = to_patches(x1, self.patch_size)
            x2 = to_patches(x2, self.patch_size)
            # Note: Mask handling for patches is more complex and not implemented here
            raise NotImplementedError("Mask with patch_size is not supported yet")

        assert x1.shape == x2.shape, "Input images must be the same size"
        # Apply circular mask
        x1 = x1 * self.mask
        x2 = x2 * self.mask

        _, c, h, w = x1.shape
        x1, x2 = self.norm(x1), self.norm(x2)

        score = torch.einsum("b...,b...->b", x1, x2)
        effective_pixels = c * self.mask.sum()  # Total valid pixels per batch
        score /= effective_pixels + self.eps

        return score

    def norm(self, x):
        mask = self.mask.expand_as(x)

        mu = (x * mask).sum(dim=[-2, -1], keepdim=True) / (mask.sum(dim=[-2, -1], keepdim=True) + self.eps)
        x_centered = (x - mu) * mask
        var = (x_centered ** 2).sum(dim=[-2, -1], keepdim=True) / (mask.sum(dim=[-2, -1], keepdim=True) + self.eps)
        std = var.sqrt()
        return x_centered / (std + self.eps)


class MultiscaleNormalizedCrossCorrelation2d(torch.nn.Module):
    """Compute Normalized Cross Correlation between two batches of images at multiple scales."""

    def __init__(self, patch_sizes=[None], patch_weights=[1.0], eps=1e-5, device=torch.device('cpu')):
        super().__init__()

        assert len(patch_sizes) == len(patch_weights), "Each scale must have a weight"
        self.nccs = [
            NormalizedCrossCorrelation2d(patch_size, device=device) for patch_size in patch_sizes
        ]
        self.patch_weights = patch_weights

    def forward(self, x1, x2):
        scores = []
        for weight, ncc in zip(self.patch_weights, self.nccs):
            scores.append(weight * ncc(x1, x2))
        return torch.stack(scores, dim=0).sum(dim=0)

